40	/*! Return a list of dirty properties from a node
41	 */
42	auto get_dirty_props(graph_t::node_ref_t node_ref)
43	{
44	    using namespace uhd::rfnoc;
45	    node_accessor_t node_accessor{};
46	    return node_accessor.filter_props(node_ref, [](property_base_t* prop) {
47	        return prop->is_dirty()
48	               && prop->get_src_info().type != res_source_info::FRAMEWORK;
49	    });
50	}
