54	/*! Graph-filtering predicate to find dirty nodes only
55	 */
56	struct graph_t::impl::DirtyNodePredicate
57	{
58	    DirtyNodePredicate() {} // Default ctor is required
59	    DirtyNodePredicate(graph_t::impl::rfnoc_graph_t& graph) : _graph(&graph) {}
60	
61	    template <typename Vertex>
62	    bool operator()(const Vertex& v) const
63	    {
64	        return !get_dirty_props(
65	            boost::get(graph_t::impl::vertex_property_t(), *_graph, v))
66	                    .empty();
67	    }
68	
69	private:
70	    // Don't make any attribute const, because default assignment operator
71	    // is also required
72	    graph_t::impl::rfnoc_graph_t* _graph;
73	};
