100	 *****************************************************************************/
101	void graph_t::impl::connect(
102	    node_ref_t src_node, node_ref_t dst_node, graph_edge_t edge_info)
103	{
104	    std::lock_guard<std::recursive_mutex> l(_graph_mutex);
105	
106	    node_accessor_t node_accessor{};
107	    UHD_LOG_TRACE(LOG_ID,
108	        "Connecting block " << src_node->get_unique_id() << ":" << edge_info.src_port
109	                            << " -> " << dst_node->get_unique_id() << ":"
110	                            << edge_info.dst_port);
111	
112	    // Correctly populate edge_info
113	    edge_info.src_blockid = src_node->get_unique_id();
114	    edge_info.dst_blockid = dst_node->get_unique_id();
115	
116	    // Add nodes to graph, if not already in there:
117	    _add_node(src_node);
118	    _add_node(dst_node);
119	    // Find vertex descriptors
120	    auto src_vertex_desc = _node_map.at(src_node);
121	    auto dst_vertex_desc = _node_map.at(dst_node);
122	
123	    // Set resolver callbacks:
124	    node_accessor.set_resolve_all_callback(src_node, [this, src_node]() {
125	        this->resolve_all_properties(resolve_context::NODE_PROP, src_node);
126	    });
127	    node_accessor.set_resolve_all_callback(dst_node, [this, dst_node]() {
128	        this->resolve_all_properties(resolve_context::NODE_PROP, dst_node);
129	    });
130	    node_accessor.set_graph_mutex_callback(
131	        src_node, [this]() -> std::recursive_mutex& { return this->get_graph_mutex(); });
132	    node_accessor.set_graph_mutex_callback(
133	        dst_node, [this]() -> std::recursive_mutex& { return this->get_graph_mutex(); });
134	
135	    // Set post action callbacks:
136	    node_accessor.set_post_action_callback(src_node,
137	        [this, src_node](const res_source_info& src,
138	            action_info::sptr action,
139	            uhd::rfnoc::node_t::action_mode_t mode) {
140	            this->enqueue_action(src_node, src, action, mode);
141	        });
142	    node_accessor.set_post_action_callback(dst_node,
143	        [this, dst_node](const res_source_info& src,
144	            action_info::sptr action,
145	            uhd::rfnoc::node_t::action_mode_t mode) {
146	            this->enqueue_action(dst_node, src, action, mode);
147	        });
148	
149	    // Check if edge exists
150	    auto out_edge_range = boost::out_edges(src_vertex_desc, _graph);
151	    for (auto edge_it = out_edge_range.first; edge_it != out_edge_range.second;
152	         ++edge_it) {
153	        auto existing_edge_info = boost::get(edge_property_t(), _graph, *edge_it);
154	
155	        // if exact edge exists, do nothing and return
156	        if (existing_edge_info == edge_info) {
157	            UHD_LOG_INFO(LOG_ID,
158	                "Ignoring repeated call to connect "
159	                    << edge_info.src_blockid << ":" << edge_info.src_port << " -> "
160	                    << edge_info.dst_blockid << ":" << edge_info.dst_port);
161	            return;
162	        }
163	
164	        // if there is already an edge for the source block and port
165	        if (existing_edge_info.src_port == edge_info.src_port
166	            && existing_edge_info.src_blockid == edge_info.src_blockid) {
167	            // if same destination block and port
168	            if (existing_edge_info.dst_port == edge_info.dst_port
169	                && existing_edge_info.dst_blockid == edge_info.dst_blockid) {
170	                // attempt to modify edge properties - throw an error
171	                UHD_LOG_ERROR(LOG_ID,
172	                    "Caught attempt to modify properties of edge "
173	                        << existing_edge_info.src_blockid << ":"
174	                        << existing_edge_info.src_port << " -> "
175	                        << existing_edge_info.dst_blockid << ":"
176	                        << existing_edge_info.dst_port);
177	                throw uhd::rfnoc_error("Caught attempt to modify properties of edge!");
178	            } else {
179	                // Attempt to reconnect already connected source block and port
180	                UHD_LOG_ERROR(LOG_ID,
181	                    "Attempting to reconnect output port "
182	                        << existing_edge_info.src_blockid << ":"
183	                        << existing_edge_info.src_port);
184	                throw uhd::rfnoc_error("Attempting to reconnect output port!");
185	            }
186	        }
187	    }
188	    auto in_edge_range = boost::in_edges(dst_vertex_desc, _graph);
189	    for (auto edge_it = in_edge_range.first; edge_it != in_edge_range.second; ++edge_it) {
190	        auto existing_edge_info = boost::get(edge_property_t(), _graph, *edge_it);
191	        if (edge_info.dst_blockid == existing_edge_info.dst_blockid
192	            && edge_info.dst_port == existing_edge_info.dst_port) {
193	            UHD_LOG_ERROR(LOG_ID,
194	                "Attempting to reconnect input port " << existing_edge_info.dst_blockid
195	                                                      << ":"
196	                                                      << existing_edge_info.dst_port);
197	            throw uhd::rfnoc_error("Attempting to reconnect input port!");
198	        }
199	    }
200	
201	    // Create edge
202	    auto edge_descriptor =
203	        boost::add_edge(src_vertex_desc, dst_vertex_desc, edge_info, _graph);
204	    UHD_ASSERT_THROW(edge_descriptor.second);
205	
206	    // Now make sure we didn't add an unintended cycle
207	    try {
208	        _get_topo_sorted_nodes();
209	    } catch (const uhd::rfnoc_error&) {
210	        UHD_LOG_ERROR(LOG_ID,
211	            "Adding edge " << src_node->get_unique_id() << ":" << edge_info.src_port
212	                           << " -> " << dst_node->get_unique_id() << ":"
213	                           << edge_info.dst_port
214	                           << " without disabling is_forward_edge will lead "
215	                              "to unresolvable graph!");
216	        boost::remove_edge(edge_descriptor.first, _graph);
217	        throw uhd::rfnoc_error("Adding edge without disabling is_forward_edge will lead "
218	                               "to unresolvable graph!");
219	    }
220	}
