222	void graph_t::impl::disconnect(
223	    node_ref_t src_node, node_ref_t dst_node, graph_edge_t edge_info)
224	{
225	    std::lock_guard<std::recursive_mutex> l(_graph_mutex);
226	
227	    node_accessor_t node_accessor{};
228	
229	    // Find vertex descriptor
230	    if (_node_map.count(src_node) == 0 && _node_map.count(dst_node) == 0) {
231	        return;
232	    }
233	
234	    UHD_LOG_TRACE(LOG_ID,
235	        "Disconnecting block " << src_node->get_unique_id() << ":" << edge_info.src_port
236	                               << " -> " << dst_node->get_unique_id() << ":"
237	                               << edge_info.dst_port);
238	
239	    auto src_vertex_desc = _node_map.at(src_node);
240	    auto dst_vertex_desc = _node_map.at(dst_node);
241	
242	    edge_info.src_blockid = src_node->get_unique_id();
243	    edge_info.dst_blockid = dst_node->get_unique_id();
244	
245	    boost::remove_out_edge_if(
246	        src_vertex_desc,
247	        [this, edge_info](rfnoc_graph_t::edge_descriptor edge_desc) {
248	            return (edge_info.is_equal(
249	                boost::get(edge_property_t(), this->_graph, edge_desc), false));
250	        },
251	        _graph);
252	
253	    if (boost::degree(src_vertex_desc, _graph) == 0) {
254	        _remove_node(src_node);
255	        UHD_LOG_TRACE(LOG_ID,
256	            "Removing block " << src_node->get_unique_id() << ":" << edge_info.src_port);
257	        node_accessor.clear_resolve_all_callback(src_node);
258	        node_accessor.clear_graph_mutex_callback(src_node);
259	        node_accessor.set_post_action_callback(src_node,
260	            [](const res_source_info&,
261	                action_info::sptr,
262	                uhd::rfnoc::node_t::action_mode_t) {});
263	    }
264	
265	    // Re-look up the vertex descriptor for dst_node, as the act of removing
266	    // src_node may have modified it
267	    dst_vertex_desc = _node_map.at(dst_node);
268	    if (boost::degree(dst_vertex_desc, _graph) == 0) {
269	        _remove_node(dst_node);
270	        UHD_LOG_TRACE(LOG_ID,
271	            "Removing block " << dst_node->get_unique_id() << ":" << edge_info.dst_port);
272	        node_accessor.clear_resolve_all_callback(dst_node);
273	        node_accessor.clear_graph_mutex_callback(dst_node);
274	        node_accessor.set_post_action_callback(dst_node,
275	            [](const res_source_info&,
276	                action_info::sptr,
277	                uhd::rfnoc::node_t::action_mode_t) {});
278	    }
279	}
