287	void graph_t::impl::commit()
288	{
289	    std::lock_guard<std::recursive_mutex> l(_graph_mutex);
290	    if (_release_count) {
291	        _release_count--;
292	    }
293	    if (_release_count == 0) {
294	        _check_topology();
295	        std::lock_guard<std::recursive_mutex> l(_graph_mutex);
296	        resolve_all_properties(resolve_context::INIT, *boost::vertices(_graph).first);
297	    }
298	}
