300	void graph_t::impl::release()
301	{
302	    std::lock_guard<std::recursive_mutex> l(_graph_mutex);
303	    UHD_LOG_TRACE(LOG_ID, "graph::release() => " << _release_count);
304	    _release_count++;
305	}
