307	void graph_t::impl::shutdown()
308	{
309	    std::lock_guard<std::recursive_mutex> l(_graph_mutex);
310	    UHD_LOG_TRACE(LOG_ID, "graph::shutdown()");
311	    _shutdown      = true;
312	    _release_count = std::numeric_limits<size_t>::max();
313	
314	    // Notify the action handler thread to wake up and check shutdown flag
315	    _action_queue_cv.notify_all();
316	}
