318	std::vector<graph_t::impl::graph_edge_t> graph_t::impl::enumerate_edges()
319	{
320	    auto e_iterators = boost::edges(_graph);
321	    std::vector<graph_edge_t> result;
322	    for (auto e_it = e_iterators.first; e_it != e_iterators.second; ++e_it) {
323	        graph_edge_t edge_info = boost::get(edge_property_t(), _graph, *e_it);
324	        // This is probably the dumbest way to make sure that the in- and out-
325	        // edges don't both get stashed, but it works for now
326	        if (std::find(result.begin(), result.end(), edge_info) == result.end()) {
327	            result.push_back(boost::get(edge_property_t(), _graph, *e_it));
328	        }
329	    }
330	    return result;
331	}
