333	std::string graph_t::impl::to_dot()
334	{
335	    std::string result("digraph rfnoc_graph {\n"
336	                       "  rankdir=LR\n"
337	                       "  node [shape=record]\n\n");
338	
339	    for (const auto& elem : _node_map) {
340	        // add block, prepend with cluster,
341	        // the cluster prefix ensures a box around the node
342	        result += str(boost::format("  subgraph \"cluster_%s\" {\n"
343	                                    "    label=\"%s\"\n")
344	                      % elem.first->get_unique_id() % elem.first->get_unique_id());
345	
346	        // add input ports as joint blocks using "|<ref> label" notation
347	        if (elem.first->get_num_input_ports() > 0) {
348	            result += str(
349	                boost::format("    \"%s_in\" [label=\"in") % elem.first->get_unique_id());
350	            for (size_t i = 0; i < elem.first->get_num_input_ports(); i++) {
351	                result += str(boost::format("|<in_%d> %d") % i % i);
352	            }
353	            result += "\"]\n";
354	        }
355	
356	        // add input ports as joint blocks using "|<ref> label" notation
357	        if (elem.first->get_num_output_ports() > 0) {
358	            result += str(boost::format("    \"%s_out\" [label=\"out")
359	                          % elem.first->get_unique_id());
360	            for (size_t i = 0; i < elem.first->get_num_output_ports(); i++) {
361	                result += str(boost::format("|<out_%d> %d") % i % i);
362	            }
363	            result += "\"]\n";
364	        }
365	
366	        result += "  }\n";
367	
368	        // add an invisible connection between in and out ports so they
369	        // get aligned inputs left and outputs right
370	        if ((elem.first->get_num_input_ports() > 0)
371	            && (elem.first->get_num_output_ports() > 0)) {
372	            result += str(boost::format("  \"%s_in\" -> \"%s_out\" [style=invis]\n")
373	                          % elem.first->get_unique_id() % elem.first->get_unique_id());
374	        }
375	        result += "\n";
376	    }
377	    result += "\n";
378	
379	    static const std::map<uhd::rfnoc::graph_edge_t::edge_t, std::string> edge_format_map =
380	        {{uhd::rfnoc::graph_edge_t::edge_t::DYNAMIC, "label=\"dynamic\""},
381	            {uhd::rfnoc::graph_edge_t::edge_t::STATIC,
382	                "color=\"black:white:black\",label=\"static\",weight=10"},
383	            {uhd::rfnoc::graph_edge_t::edge_t::RX_STREAM,
384	                "style=\"dashed\",label=\"RX stream\""},
385	            {uhd::rfnoc::graph_edge_t::edge_t::TX_STREAM,
386	                "style=\"dashed\",label=\"TX stream\""}};
387	
388	    // add current connections
389	    for (const auto& elem : enumerate_edges()) {
390	        result +=
391	            str(boost::format("  \"%s_out\":\"out_%d\" -> \"%s_in\":\"in_%d\" [%s]\n")
392	                % elem.src_blockid % elem.src_port % elem.dst_blockid % elem.dst_port
393	                % edge_format_map.at(elem.edge));
394	    }
395	    result += "}\n";
396	    return result;
397	}
