400	 * Private methods to be called by friends
401	 *****************************************************************************/
402	void graph_t::impl::resolve_all_properties(
403	    resolve_context context, rfnoc_graph_t::vertex_descriptor initial_node)
404	{
405	    if (boost::num_vertices(_graph) == 0) {
406	        return;
407	    }
408	
409	    if (_shutdown) {
410	        return;
411	    }
412	    if (_release_count) {
413	        node_accessor_t node_accessor{};
414	        node_ref_t current_node = boost::get(vertex_property_t(), _graph, initial_node);
415	        UHD_LOG_TRACE(LOG_ID,
416	            "Only resolving node " << current_node->get_unique_id()
417	                                   << ", graph is not committed!");
418	        // On current node, call local resolution.
419	        node_accessor.resolve_props(current_node);
420	        // Now mark all properties on this node as clean
421	        node_accessor.clean_props(current_node);
422	        return;
423	    }
424	
425	    UHD_LOG_TRACE(LOG_ID, "Running forward edge property propagation...");
426	    _resolve_all_properties(context, initial_node, true);
427	    UHD_LOG_TRACE(LOG_ID, "Running backward edge property propagation...");
428	    _resolve_all_properties(context, initial_node, false);
429	}
430	
431	
432	void graph_t::impl::_resolve_all_properties(resolve_context context,
433	    rfnoc_graph_t::vertex_descriptor initial_node,
434	    const bool forward)
435	{
436	    node_accessor_t node_accessor{};
437	
438	    // First, find the node on which we'll start.
439	    auto initial_dirty_nodes = _find_dirty_nodes();
440	    if (initial_dirty_nodes.size() > 1) {
441	        UHD_LOGGER_WARNING(LOG_ID)
442	            << "Found " << initial_dirty_nodes.size()
443	            << " dirty nodes in initial search (expected one or zero). "
444	               "Property propagation may resolve this.";
445	        for (auto& vertex : initial_dirty_nodes) {
446	            node_ref_t node = boost::get(vertex_property_t(), _graph, vertex);
447	            UHD_LOG_WARNING(LOG_ID, "Dirty: " << node->get_unique_id());
448	        }
449	    }
450	
451	    // Now get all nodes in topologically sorted order, and the appropriate
452	    // iterators.
453	    auto topo_sorted_nodes = _get_topo_sorted_nodes();
454	    auto node_it           = topo_sorted_nodes.begin();
455	    auto begin_it          = topo_sorted_nodes.begin();
456	    auto end_it            = topo_sorted_nodes.end();
457	    while (*node_it != initial_node) {
458	        if (node_it == end_it) {
459	            throw uhd::rfnoc_error("Cannot find node in graph!");
460	        }
461	        // We know *node_it must be == initial_node at some point, because
462	        // otherwise, initial_dirty_nodes would have been empty
463	        node_it++;
464	    }
465	
466	    // Start iterating over nodes
467	    bool forward_dir   = true;
468	    int num_iterations = 0;
469	    // If all edge properties were known at the beginning, a single iteration
470	    // would suffice. However, usually during the first time the property
471	    // propagation is run, blocks create new (dynamic) edge properties that
472	    // default to dirty. If we had a way of knowing when that happens, we could
473	    // dynamically increase the number of iterations during the loop. For now,
474	    // we simply hard-code the number of iterations to 2 so that we catch that
475	    // case without any additional complications.
476	    constexpr int MAX_NUM_ITERATIONS = 2;
477	    while (true) {
478	        node_ref_t current_node = boost::get(vertex_property_t(), _graph, *node_it);
479	        UHD_LOG_TRACE(
480	            LOG_ID, "Now resolving next node: " << current_node->get_unique_id());
481	
482	        // On current node, call local resolution. This may cause other
483	        // properties to become dirty.
484	        try {
485	            node_accessor.resolve_props(current_node);
486	        } catch (const uhd::resolve_error& ex) {
487	            UHD_LOG_ERROR(LOG_ID, current_node->get_unique_id() + ": " + ex.what());
488	            throw;
489	        }
490	
491	        //  Forward all edge props in all directions from current node. We only
492	        //  forward properties across edges that either forward- or back-edges,
493	        //  depending on `forward`.
494	        _forward_edge_props(*node_it, forward);
495	
496	        // Now mark all properties on this node as clean
497	        node_accessor.clean_props(current_node);
498	
499	        // If the property resolution was triggered by a node updating one of
500	        // its properties, we can stop anytime there are no more dirty nodes.
501	        if (context == resolve_context::NODE_PROP && _find_dirty_nodes().empty()) {
502	            UHD_LOG_TRACE(LOG_ID,
503	                "Terminating graph resolution early during iteration " << num_iterations);
504	            break;
505	        }
506	
507	        // The rest of the code in this loop is to figure out who's the next
508	        // node. First, increment (or decrement) iterator:
509	        if (forward_dir) {
510	            node_it++;
511	            // If we're at the end, flip the direction
512	            if (node_it == end_it) {
513	                forward_dir = false;
514	                // Back off from the sentinel:
515	                node_it--;
516	            }
517	        }
518	        if (!forward_dir) {
519	            if (topo_sorted_nodes.size() > 1) {
520	                node_it--;
521	                // If we're back at the front, flip direction
522	                if (node_it == begin_it) {
523	                    forward_dir = true;
524	                }
525	            } else {
526	                forward_dir = true;
527	            }
528	        }
529	        // If we're going forward, and the next node is the initial node,
530	        // we've gone full circle (one full iteration).
531	        if (forward_dir && (*node_it == initial_node)) {
532	            num_iterations++;
533	            if (num_iterations == MAX_NUM_ITERATIONS || _find_dirty_nodes().empty()) {
534	                UHD_LOG_TRACE(LOG_ID,
535	                    "Terminating graph resolution after iteration " << num_iterations);
536	                break;
537	            }
538	        }
539	    }
540	
541	    // Post-iteration sanity checks:
542	    // Make sure that there are no dirty properties left. If there are,
543	    // that means our algorithm couldn't converge and we have a problem.
544	    auto remaining_dirty_nodes = _find_dirty_nodes();
545	    if (!remaining_dirty_nodes.empty()) {
546	        UHD_LOG_ERROR(LOG_ID, "The following properties could not be resolved:");
547	        for (auto& vertex : remaining_dirty_nodes) {
548	            node_ref_t node           = boost::get(vertex_property_t(), _graph, vertex);
549	            const std::string node_id = node->get_unique_id();
550	            auto dirty_props          = get_dirty_props(node);
551	            for (auto& prop : dirty_props) {
552	                UHD_LOG_ERROR(LOG_ID,
553	                    "Dirty: " << node_id << "[" << prop->get_src_info().to_string() << " "
554	                              << prop->get_id() << "]");
555	            }
556	        }
557	        throw uhd::resolve_error("Could not resolve properties.");
558	    }
559	}
