573	void graph_t::impl::enqueue_action(node_ref_t src_node,
574	    res_source_info src_edge,
575	    action_info::sptr action,
576	    uhd::rfnoc::node_t::action_mode_t mode)
577	{
578	    if (_shutdown) {
579	        return;
580	    }
581	
582	    UHD_LOG_TRACE(LOG_ID,
583	        "Enqueuing action asynchronously " << action->key << "#" << action->id << " from "
584	                                           << src_node->get_unique_id());
585	    // Enqueue the action in thread-safe manner and notify the handler thread
586	    {
587	        std::lock_guard<std::mutex> queue_lock(_action_queue_mutex);
588	        _action_queue.emplace_back(std::make_tuple(src_node, src_edge, action));
589	        UHD_LOG_TRACE(LOG_ID,
590	            "Enqueued action " << action->key << "#" << action->id << " from "
591	                               << src_node->get_unique_id());
592	        _action_queue_cv.notify_all();
593	    }
594	
595	    // If the user requested synchronous operation, we wait for the action
596	    // handling cascade to finish. However, this is not allowed when we're in
597	    // the action handler thread.
598	    // This is also where exceptions get thrown, should they have occurred in
599	    // the action handler thread.
600	    if (mode == uhd::rfnoc::node_t::action_mode_t::SYNC
601	        && std::this_thread::get_id() != _action_handler_thread_id) {
602	        sync_actions();
603	    }
604	}
605	
606	void graph_t::impl::sync_actions()
607	{
608	    // Wait for the action queue to be empty AND no action is currently being processed
609	    auto exit_condition = [this]() -> bool {
610	        return (_action_queue.empty() && !_action_processing) || _shutdown;
611	    };
612	    std::unique_lock<std::mutex> lock(_action_queue_mutex);
613	    constexpr auto POLL_CV_TIMEOUT = 10ms;
614	    while (!exit_condition()) {
615	        if (_action_queue_cv.wait_for(lock, POLL_CV_TIMEOUT, exit_condition)) {
616	            break;
617	        }
618	    }
619	
620	    if (_action_eptr) {
621	        std::rethrow_exception(_action_eptr);
622	    }
623	}
624	
625	void graph_t::impl::_action_handler()
626	{
627	    UHD_LOG_TRACE(LOG_ID, "Action handler thread started");
628	
629	    while (true) {
630	        std::unique_lock<std::mutex> lock(_action_queue_mutex);
631	
632	        // Wait for actions to be available or shutdown to be signaled
633	        _action_queue_cv.wait(
634	            lock, [this] { return !_action_queue.empty() || _shutdown; });
635	        // Release action queue lock until we need to pop an action from the q
636	        lock.unlock();
637	
638	        // Hold the graph mutex while processing actions to prevent releases
639	        // and other graph operations during action handling
640	        std::lock_guard<std::recursive_mutex> graph_lock(_graph_mutex);
641	
642	        // Check for shutdown
643	        if (_shutdown) {
644	            UHD_LOG_TRACE(LOG_ID, "Action handler thread shutting down");
645	            break;
646	        }
647	
648	        // Track ongoing action handling for sync_actions(), so it doesn't
649	        // prematurely exit.
650	        _action_processing = true;
651	
652	        // Process all available actions
653	        try {
654	            _process_action_queue();
655	        } catch (const std::exception& ex) {
656	            UHD_LOG_ERROR(
657	                "RFNOC", "Caught exception during action handling: " << ex.what());
658	            _action_eptr = std::current_exception();
659	        } catch (...) {
660	            UHD_LOG_ERROR("RFNOC", "Caught unknown exception during action handling! ");
661	            _action_eptr = std::current_exception();
662	        }
663	
664	        _action_processing = false;
665	        _action_queue_cv.notify_all(); // Notify sync_actions() waiters
666	    }
667	
668	    UHD_LOG_TRACE(LOG_ID, "Action handler thread terminated");
669	}
670	
671	// Precondition: Caller must be holding the graph mutex.
672	void graph_t::impl::_process_action_queue()
673	{
674	    std::unique_lock<std::mutex> queue_lock(_action_queue_mutex);
675	    unsigned iteration_count = 0;
676	    while (!_action_queue.empty()) {
677	        if (_shutdown) {
678	            return;
679	        }
680	        if (iteration_count++ == MAX_ACTION_ITERATIONS) {
681	            UHD_LOG_ERROR(
682	                LOG_ID, "Terminating action handling: Reached recursion limit!");
683	            // Drop actions to logging interface
684	            for (const auto& action : _action_queue) {
685	                UHD_LOG_ERROR(LOG_ID,
686	                    "Dropping action from queue due to recursion limit: "
687	                        << std::get<2>(action)->key << "#" << std::get<2>(action)->id
688	                        << " from " << std::get<0>(action)->get_unique_id());
689	            }
690	            _action_queue.clear();
691	            break;
692	        }
693	
694	        // Get the next action
695	        auto next_action = std::move(_action_queue.front());
696	        _action_queue.pop_front();
697	
698	        // Release the queue lock while processing the action, and reacquire
699	        // afterwards. If more actions are enqueued while we are running, that's
700	        // fine.
701	        queue_lock.unlock();
702	        if (_release_count) {
703	            UHD_LOG_WARNING(LOG_ID,
704	                "Action propagation is not enabled, graph is not committed! Will not "
705	                "propagate action `"
706	                    << std::get<2>(next_action)->key << "'");
707	        } else {
708	            _process_action(std::get<0>(next_action),
709	                std::get<1>(next_action),
710	                std::get<2>(next_action));
711	        }
712	        queue_lock.lock();
713	    }
714	}
715	
716	// Precondition: Caller must be holding the graph mutex.
717	void graph_t::impl::_process_action(
718	    node_ref_t src_node, res_source_info src_edge, action_info::sptr action)
719	{
720	    if (_shutdown) {
721	        return;
722	    }
723	
724	    // Find the node that is supposed to receive this action, and if we find
725	    // something, then send the action. If the source port's type is USER,
726	    // that means the action is meant for us.
727	    node_ref_t recipient_node;
728	    res_source_info recipient_port(src_edge);
729	
730	    if (src_edge.type == res_source_info::USER) {
731	        recipient_node = src_node;
732	        recipient_port = src_edge;
733	    } else {
734	        auto recipient_info = _find_neighbour(_node_map.at(src_node), src_edge);
735	        recipient_node      = recipient_info.first;
736	        if (recipient_node == nullptr) {
737	            UHD_LOG_WARNING(LOG_ID,
738	                "Cannot forward action "
739	                    << action->key << " from " << src_node->get_unique_id() << ":"
740	                    << src_edge.to_string() << ", no neighbour found!");
741	            return;
742	        }
743	        recipient_port = {res_source_info::invert_edge(src_edge.type),
744	            src_edge.type == res_source_info::INPUT_EDGE
745	                ? recipient_info.second.src_port
746	                : recipient_info.second.dst_port};
747	    }
748	
749	    // Deliver the action to the recipient node
750	    UHD_LOG_TRACE(LOG_ID,
751	        "Delivering action " << action->key << "#" << action->id << " to "
752	                             << recipient_node->get_unique_id() << "@"
753	                             << recipient_port.to_string());
754	    node_accessor_t{}.send_action(recipient_node, recipient_port, action);
755	}
