760	graph_t::impl::vertex_list_t graph_t::impl::_find_dirty_nodes()
761	{
762	    // Create a view on the graph that doesn't include the back-edges
763	    DirtyNodePredicate vertex_filter(_graph);
764	    boost::filtered_graph<rfnoc_graph_t, boost::keep_all, DirtyNodePredicate> fg(
765	        _graph, boost::keep_all(), vertex_filter);
766	
767	    auto v_iterators = boost::vertices(fg);
768	    return vertex_list_t(v_iterators.first, v_iterators.second);
