771	graph_t::impl::vertex_list_t graph_t::impl::_get_topo_sorted_nodes()
772	{
773	    // Create a view on the graph that doesn't include the back-edges
774	    ForwardEdgePredicate edge_filter(_graph);
775	    boost::filtered_graph<rfnoc_graph_t, ForwardEdgePredicate> fg(_graph, edge_filter);
776	
777	    // Topo-sort and return
778	    vertex_list_t sorted_nodes;
779	    try {
780	        boost::topological_sort(fg, std::front_inserter(sorted_nodes));
781	    } catch (boost::not_a_dag&) {
782	        throw uhd::rfnoc_error("Cannot resolve graph because it has at least one cycle!");
783	    }
784	    return sorted_nodes;
785	}
