796	void graph_t::impl::_remove_node(node_ref_t node)
797	{
798	    if (_node_map.count(node)) {
799	        auto vertex_desc = _node_map.at(node);
800	
801	        // Remove all edges
802	        boost::clear_vertex(vertex_desc, _graph);
803	
804	        // Remove the vertex
805	        boost::remove_vertex(vertex_desc, _graph);
806	        _node_map.erase(node);
807	
808	        // Removing the vertex changes the vertex descriptors,
809	        // so update the node map
810	        auto vertex_range = boost::vertices(_graph);
811	        for (auto vertex_it = vertex_range.first; vertex_it != vertex_range.second;
812	             vertex_it++) {
813	            auto node       = boost::get(vertex_property_t(), _graph, *vertex_it);
814	            _node_map[node] = *vertex_it;
815	        }
816	    }
