820	void graph_t::impl::_forward_edge_props(
821	    graph_t::impl::rfnoc_graph_t::vertex_descriptor origin, const bool forward)
822	{
823	    node_accessor_t node_accessor{};
824	    node_ref_t origin_node = boost::get(vertex_property_t(), _graph, origin);
825	
826	    auto edge_props = node_accessor.filter_props(origin_node, [](property_base_t* prop) {
827	        return (prop->get_src_info().type == res_source_info::INPUT_EDGE
828	                || prop->get_src_info().type == res_source_info::OUTPUT_EDGE);
829	    });
830	    UHD_LOG_TRACE(LOG_ID,
831	        "Forwarding up to " << edge_props.size() << " edge properties from node "
832	                            << origin_node->get_unique_id() << " along "
833	                            << (forward ? "forward" : "back") << " edges.");
834	
835	    for (auto prop : edge_props) {
836	        auto neighbour_node_info = _find_neighbour(origin, prop->get_src_info());
837	        if (neighbour_node_info.first != nullptr
838	            && neighbour_node_info.second.is_forward_edge == forward) {
839	            const size_t neighbour_port = prop->get_src_info().type
840	                                                  == res_source_info::INPUT_EDGE
841	                                              ? neighbour_node_info.second.src_port
842	                                              : neighbour_node_info.second.dst_port;
843	            node_accessor.forward_edge_property(
844	                neighbour_node_info.first, neighbour_port, prop);
845	        }
846	    }
847	}
