849	bool graph_t::impl::_assert_edge_props_consistent(rfnoc_graph_t::edge_descriptor edge)
850	{
851	    node_ref_t src_node =
852	        boost::get(vertex_property_t(), _graph, boost::source(edge, _graph));
853	    node_ref_t dst_node =
854	        boost::get(vertex_property_t(), _graph, boost::target(edge, _graph));
855	    graph_edge_t edge_info = boost::get(edge_property_t(), _graph, edge);
856	
857	    // Helper function to get properties as maps
858	    auto get_prop_map = [](const size_t port,
859	                            res_source_info::source_t edge_type,
860	                            node_ref_t node) {
861	        node_accessor_t node_accessor{};
862	        // Create a set of all properties
863	        auto props_set =
864	            node_accessor.filter_props(node, [port, edge_type](property_base_t* prop) {
865	                return prop->get_src_info().instance == port
866	                       && prop->get_src_info().type == edge_type;
867	            });
868	        std::unordered_map<std::string, property_base_t*> prop_map;
869	        for (auto prop_it = props_set.begin(); prop_it != props_set.end(); ++prop_it) {
870	            prop_map.emplace((*prop_it)->get_id(), *prop_it);
871	        }
872	
873	        return prop_map;
874	    };
875	
876	    // Create two maps ID -> prop_ptr, so we have an easier time comparing them
877	    auto src_prop_map =
878	        get_prop_map(edge_info.src_port, res_source_info::OUTPUT_EDGE, src_node);
879	    auto dst_prop_map =
880	        get_prop_map(edge_info.dst_port, res_source_info::INPUT_EDGE, dst_node);
881	
882	    // Now iterate through all properties, and make sure they match
883	    bool props_match = true;
884	    for (auto src_prop_it = src_prop_map.begin(); src_prop_it != src_prop_map.end();
885	         ++src_prop_it) {
886	        auto src_prop = src_prop_it->second;
887	        if (dst_prop_map.count(src_prop->get_id()) == 0) {
888	            UHD_LOG_DEBUG(LOG_ID,
889	                "On back-edge "
890	                    << edge_info.to_string() << ", source block has edge property `"
891	                    << src_prop->get_id() << "', but destination block does not.");
892	            continue;
893	        }
894	        auto dst_prop = dst_prop_map.at(src_prop->get_id());
895	        if (!src_prop->equal(dst_prop)) {
896	            UHD_LOG_ERROR(LOG_ID,
897	                "Edge property " << src_prop->get_id() << " inconsistent on edge "
898	                                 << print_edge(src_node, dst_node, edge_info));
899	            props_match = false;
900	        }
901	    }
902	
903	    return props_match;
904	}
