906	void graph_t::impl::_check_topology()
907	{
908	    node_accessor_t node_accessor{};
909	    bool topo_ok     = true;
910	    auto v_iterators = boost::vertices(_graph);
911	    for (auto it = v_iterators.first; it != v_iterators.second; ++it) {
912	        node_ref_t node = boost::get(vertex_property_t(), _graph, *it);
913	        std::vector<size_t> connected_inputs;
914	        std::vector<size_t> connected_outputs;
915	        auto ie_iters = boost::in_edges(*it, _graph);
916	        for (auto it = ie_iters.first; it != ie_iters.second; ++it) {
917	            graph_edge_t edge_info = boost::get(edge_property_t(), _graph, *it);
918	            connected_inputs.push_back(edge_info.dst_port);
919	        }
920	        auto oe_iters = boost::out_edges(*it, _graph);
921	        for (auto it = oe_iters.first; it != oe_iters.second; ++it) {
922	            graph_edge_t edge_info = boost::get(edge_property_t(), _graph, *it);
923	            connected_outputs.push_back(edge_info.src_port);
924	        }
925	
926	        if (!node_accessor.check_topology(node, connected_inputs, connected_outputs)) {
927	            std::ostringstream input_topology;
928	            input_topology << " requested inputs: (";
929	            for (auto connected_input : connected_inputs) {
930	                input_topology << connected_input;
931	                if (connected_input != connected_inputs.back()) {
932	                    input_topology << ", ";
933	                }
934	            }
935	            input_topology << ")";
936	            input_topology << " valid inputs: (";
937	            for (size_t expected_input = 0; expected_input < node->get_num_input_ports();
938	                 expected_input++) {
939	                input_topology << expected_input;
940	                if (expected_input < node->get_num_input_ports() - 1) {
941	                    input_topology << ", ";
942	                }
943	            }
944	            input_topology << ")";
945	
946	            std::ostringstream output_topology;
947	            output_topology << " requested outputs: (";
948	            for (auto connected_output : connected_outputs) {
949	                output_topology << connected_output;
950	                if (connected_output != connected_outputs.back()) {
951	                    output_topology << ", ";
952	                }
953	            }
954	            output_topology << ")";
955	            output_topology << " valid outputs: (";
956	            for (size_t expected_output = 0;
957	                 expected_output < node->get_num_output_ports();
958	                 expected_output++) {
959	                output_topology << expected_output;
960	                if (expected_output < node->get_num_output_ports() - 1) {
961	                    output_topology << ", ";
962	                }
963	            }
964	            output_topology << ")";
965	
966	            UHD_LOG_ERROR(LOG_ID,
967	                "Node " << node->get_unique_id() << " using invalid inputs or outputs! "
968	                        << input_topology.str() << ", " << output_topology.str());
969	            topo_ok = false;
970	        }
971	    }
972	
973	    if (!topo_ok) {
974	        throw uhd::runtime_error("Graph topology is not valid!");
975	    }
976	}
