978	std::pair<graph_t::impl::node_ref_t, graph_t::impl::graph_edge_t>
979	graph_t::impl::_find_neighbour(
980	    rfnoc_graph_t::vertex_descriptor origin, res_source_info port_info)
981	{
982	    if (port_info.type == res_source_info::INPUT_EDGE) {
983	        auto it_range = boost::in_edges(origin, _graph);
984	        for (auto it = it_range.first; it != it_range.second; ++it) {
985	            graph_edge_t edge_info = boost::get(edge_property_t(), _graph, *it);
986	            if (edge_info.dst_port == port_info.instance) {
987	                return {
988	                    boost::get(vertex_property_t(), _graph, boost::source(*it, _graph)),
989	                    edge_info};
990	            }
991	        }
992	        return {nullptr, {}};
993	    }
994	    if (port_info.type == res_source_info::OUTPUT_EDGE) {
995	        auto it_range = boost::out_edges(origin, _graph);
996	        for (auto it = it_range.first; it != it_range.second; ++it) {
997	            graph_edge_t edge_info = boost::get(edge_property_t(), _graph, *it);
998	            if (edge_info.src_port == port_info.instance) {
999	                return {
1000	                    boost::get(vertex_property_t(), _graph, boost::target(*it, _graph)),
1001	                    edge_info};
1002	            }
1003	        }
1004	        return {nullptr, {}};
1005	    }
1006	
1007	    UHD_THROW_INVALID_CODE_PATH();
1008	}
