86	    rfnoc_graph_impl(detail::rfnoc_device::sptr dev, const uhd::device_addr_t& dev_addr)
87	    try : _device(dev), _tree(_device->get_tree()),
88	        _num_mboards(_tree->list("/mboards").size()),
89	        _block_registry(std::make_unique<detail::block_container_t>()),
90	        _graph(std::make_unique<uhd::rfnoc::detail::graph_t>()) {
91	        _mb_controllers.reserve(_num_mboards);
92	        // Now initialize all subsystems:
93	        _init_io_srv_mgr(dev_addr); // Global I/O Service Manager
94	        _init_mb_controllers();
95	        _init_gsm(); // Graph Stream Manager
96	        try {
97	            // If anything fails here, we immediately deinit all the other
98	            // blocks to avoid any more fallout, then safely bring down the
99	            // device.
100	            for (size_t mb_idx = 0; mb_idx < _num_mboards; ++mb_idx) {
101	                _init_blocks(mb_idx, dev_addr);
102	            }
103	            UHD_LOG_TRACE(LOG_ID, "Initializing properties on all blocks...");
104	            _block_registry->init_props();
105	            _init_sep_map();
106	            _init_static_connections();
107	            _init_mbc();
108	            // Start with time set to zero, but don't complain if sync fails
109	            rfnoc_graph_impl::synchronize_devices(uhd::time_spec_t(0.0), true);
110	        } catch (...) {
111	            _block_registry->shutdown();
112	            throw;
113	        }
114	    } catch (const std::exception& ex) {
115	        UHD_LOG_ERROR(LOG_ID, "Caught exception while initializing graph: " << ex.what());
116	        throw uhd::runtime_error("Failure to create rfnoc_graph.");
117	    } catch (...) {
118	        UHD_LOG_ERROR(LOG_ID, "Caught unknown exception while initializing graph!");
119	        throw uhd::runtime_error("Failure to create rfnoc_graph.");
120	    }
