152	    bool is_connectable(const block_id_t& src_blk,
153	        size_t src_port,
154	        const block_id_t& dst_blk,
155	        size_t dst_port) override
156	    {
157	        try {
158	            const std::string src_blk_info =
159	                src_blk.to_string() + ":" + std::to_string(src_port);
160	            const std::string dst_blk_info =
161	                dst_blk.to_string() + ":" + std::to_string(dst_port);
162	
163	            // Find the static edge for src_blk:src_port
164	            auto src_static_edge_o = _get_static_edge(
165	                [src_blk_id = src_blk.to_string(), src_port](const graph_edge_t& edge) {
166	                    return edge.src_blockid == src_blk_id && edge.src_port == src_port;
167	                });
168	            // If the edge doesn't exist, then it's not even connected in the
169	            // FPGA.
170	            if (!src_static_edge_o) {
171	                return false;
172	            }
173	            graph_edge_t src_static_edge = src_static_edge_o.get();
174	
175	            // Now see if it's already connected to the destination
176	            if (src_static_edge.dst_blockid == dst_blk.to_string()
177	                && src_static_edge.dst_port == dst_port) {
178	                return true;
179	            }
180	
181	            // If they're not statically connected, the source *must* be connected
182	            // to an SEP, or this route is impossible
183	            if (block_id_t(src_static_edge.dst_blockid).get_block_name() != NODE_ID_SEP) {
184	                return false;
185	            }
186	
187	            // OK, now we know which source SEP we have
188	            const std::string src_sep_info = src_static_edge.dst_blockid;
189	            // const sep_addr_t src_sep_addr  = _sep_map.at(src_sep_info);
190	
191	            // Now find the static edge for the destination SEP
192	            auto dst_static_edge_o = _get_static_edge(
193	                [dst_blk_id = dst_blk.to_string(), dst_port](const graph_edge_t& edge) {
194	                    return edge.dst_blockid == dst_blk_id && edge.dst_port == dst_port;
195	                });
196	            // If the edge doesn't exist, then it's not even connected in the
197	            // FPGA.
198	            if (!dst_static_edge_o) {
199	                return false;
200	            }
201	            graph_edge_t dst_static_edge = dst_static_edge_o.get();
202	
203	            // If they're not statically connected, the source *must* be connected
204	            // to an SEP, or this route is impossible
205	            if (block_id_t(dst_static_edge.src_blockid).get_block_name() != NODE_ID_SEP) {
206	                return false;
207	            }
208	
209	            // OK, now we know which destination SEP we have
210	            const std::string dst_sep_info = dst_static_edge.src_blockid;
211	            // const sep_addr_t dst_sep_addr  = _sep_map.at(dst_sep_info);
212	
213	            UHD_LOG_WARNING(LOG_ID,
214	                "is_connectable() currently assuming that SEPs"
215	                    << dst_sep_info << " and " << src_sep_info
216	                    << " are connectable. "
217	                       "Please implement a better check.");
218	        } catch (...) {
219	            return false;
220	        }
221	        return true;
222	    }
