225	    void connect(const block_id_t& src_blk,
226	        size_t src_port,
227	        const block_id_t& dst_blk,
228	        size_t dst_port,
229	        bool is_back_edge) override
230	    {
231	        if (!has_block(src_blk)) {
232	            throw uhd::lookup_error(
233	                std::string("Cannot connect blocks, source block not found: ")
234	                + src_blk.to_string());
235	        }
236	        if (!has_block(dst_blk)) {
237	            throw uhd::lookup_error(
238	                std::string("Cannot connect blocks, destination block not found: ")
239	                + dst_blk.to_string());
240	        }
241	        auto edge_type = _physical_connect(src_blk, src_port, dst_blk, dst_port);
242	        _connect(get_block(src_blk),
243	            src_port,
244	            get_block(dst_blk),
245	            dst_port,
246	            edge_type,
247	            is_back_edge);
248	    }
