808	    void _init_static_connections()
809	    {
810	        UHD_LOG_TRACE(LOG_ID, "Identifying static connections...");
811	        for (auto& kv_cz : _client_zeros) {
812	            auto& adjacency_list = kv_cz.second->get_adjacency_list();
813	            for (auto& edge : adjacency_list) {
814	                // Assemble edge
815	                auto graph_edge = graph_edge_t();
816	                UHD_ASSERT_THROW(
817	                    _port_block_map.count({kv_cz.first, edge.src_blk_index}));
818	                graph_edge.src_blockid =
819	                    _port_block_map.at({kv_cz.first, edge.src_blk_index});
820	                UHD_ASSERT_THROW(
821	                    _port_block_map.count({kv_cz.first, edge.dst_blk_index}));
822	                graph_edge.dst_blockid =
823	                    _port_block_map.at({kv_cz.first, edge.dst_blk_index});
824	                graph_edge.src_port = edge.src_blk_port;
825	                graph_edge.dst_port = edge.dst_blk_port;
826	                graph_edge.edge     = graph_edge_t::edge_t::STATIC;
827	                _static_edges.push_back(graph_edge);
828	                UHD_LOG_TRACE(LOG_ID, "Static connection: " << graph_edge.to_string());
829	            }
830	        }
831	    }
