845	    /*! Internal connection helper
846	     *
847	     * Make the connections in the _graph, and set up property propagation
848	     * Prerequisite: \p src_blk and \p dst_blk need to point to valid nodes
849	     */
850	    void _connect(std::shared_ptr<node_t> src_blk,
851	        size_t src_port,
852	        std::shared_ptr<node_t> dst_blk,
853	        size_t dst_port,
854	        graph_edge_t::edge_t edge_type,
855	        bool is_back_edge)
856	    {
857	        graph_edge_t edge_info(src_port, dst_port, edge_type, not is_back_edge);
858	        edge_info.src_blockid = src_blk->get_unique_id();
859	        edge_info.dst_blockid = dst_blk->get_unique_id();
860	        _graph->connect(src_blk.get(), dst_blk.get(), edge_info);
861	    }
