863	    /*! Internal helper to get route information
864	     *
865	     * Checks the validity of the route and returns route information.
866	     *
867	     * \throws uhd::routing_error
868	     *     if the routing is impossible
869	     */
870	    route_info_t _get_route_info(const block_id_t& src_blk,
871	        size_t src_port,
872	        const block_id_t& dst_blk,
873	        size_t dst_port)
874	    {
875	        graph_edge_t::edge_t edge_type = graph_edge_t::DYNAMIC;
876	
877	        const std::string src_blk_info =
878	            src_blk.to_string() + ":" + std::to_string(src_port);
879	        const std::string dst_blk_info =
880	            dst_blk.to_string() + ":" + std::to_string(dst_port);
881	
882	        // Find the static edge for src_blk:src_port
883	        auto src_static_edge = _assert_edge(
884	            _get_static_edge(
885	                [src_blk_id = src_blk.to_string(), src_port](const graph_edge_t& edge) {
886	                    return edge.src_blockid == src_blk_id && edge.src_port == src_port;
887	                }),
888	            src_blk_info);
889	
890	        // Now find the static edge for the destination SEP
891	        auto dst_static_edge = _assert_edge(
892	            _get_static_edge(
893	                [dst_blk_id = dst_blk.to_string(), dst_port](const graph_edge_t& edge) {
894	                    return edge.dst_blockid == dst_blk_id && edge.dst_port == dst_port;
895	                }),
896	            dst_blk_info);
897	
898	        // Now see if it's already connected to the destination
899	        if (src_static_edge.dst_blockid == dst_blk.to_string()
900	            && src_static_edge.dst_port == dst_port) {
901	            // Blocks are statically connected
902	            UHD_LOG_TRACE(LOG_ID,
903	                "Blocks " << src_blk_info << " and " << dst_blk_info
904	                          << " are statically connected");
905	            edge_type = graph_edge_t::STATIC;
906	        } else if (block_id_t(src_static_edge.dst_blockid).get_block_name()
907	                   != NODE_ID_SEP) {
908	            // Blocks are not statically connected and the source is not
909	            // connected to an SEP
910	            const std::string err_msg =
911	                src_blk_info + " is neither statically connected to " + dst_blk_info
912	                + " nor to an SEP! Routing impossible.";
913	            UHD_LOG_ERROR(LOG_ID, err_msg);
914	            throw uhd::routing_error(err_msg);
915	        } else if (block_id_t(dst_static_edge.src_blockid).get_block_name()
916	                   != NODE_ID_SEP) {
917	            // Blocks are not statically connected and the destination is not
918	            // connected to an SEP
919	            const std::string err_msg =
920	                dst_blk_info + " is neither statically connected to " + src_blk_info
921	                + " nor to an SEP! Routing impossible.";
922	            UHD_LOG_ERROR(LOG_ID, err_msg);
923	            throw uhd::routing_error(err_msg);
924	        }
925	
926	        return {edge_type, src_static_edge, dst_static_edge};
927	    }
928	
929	    /*! Internal physical connection helper
930	     *
931	     * Make the connections in the physical device
932	     *
933	     * \throws uhd::routing_error
934	     *     if the routing is impossible
935	     */
936	    graph_edge_t::edge_t _physical_connect(const block_id_t& src_blk,
937	        size_t src_port,
938	        const block_id_t& dst_blk,
939	        size_t dst_port)
940	    {
941	        auto route_info = _get_route_info(src_blk, src_port, dst_blk, dst_port);
942	
943	        if (route_info.edge_type == graph_edge_t::DYNAMIC) {
944	            const std::string src_sep_info = route_info.src_static_edge.dst_blockid;
945	            const sep_addr_t src_sep_addr  = _sep_map.at(src_sep_info);
946	            const std::string dst_sep_info = route_info.dst_static_edge.src_blockid;
947	            const sep_addr_t dst_sep_addr  = _sep_map.at(dst_sep_info);
948	
949	            auto strm_info = _gsm->create_device_to_device_data_stream(
950	                dst_sep_addr, src_sep_addr, false, 0.1, 0.0, false);
951	
952	            UHD_LOGGER_DEBUG(LOG_ID)
953	                << boost::format(
954	                       "Data stream between EPID %d and EPID %d established "
955	                       "where downstream buffer can hold %lu bytes and %u packets")
956	                       % std::get<0>(strm_info).first % std::get<0>(strm_info).second
957	                       % std::get<1>(strm_info).bytes % std::get<1>(strm_info).packets;
958	        }
959	
960	        return route_info.edge_type;
961	    }
