984	    //! Flush and reset each connected port on the mboard
985	    void _flush_and_reset_mboard(detail::client_zero::sptr mb_cz,
986	        const size_t num_blocks,
987	        const size_t first_block_port)
988	    {
989	        if (!mb_cz->complete_flush_all_blocks()) {
990	            UHD_LOG_WARNING(LOG_ID, "One or more blocks timed out during flush!");
991	        }
992	
993	        // Reset
994	        for (size_t portno = 0; portno < num_blocks; ++portno) {
995	            auto block_portno = portno + first_block_port;
996	            mb_cz->reset_chdr(block_portno);
997	            mb_cz->reset_ctrl(block_portno);
998	        }
999	    }
