179	typedef std::function<uhd::sensor_value_t(const std::string&)> get_sensor_fn_t;
180	
181	bool check_locked_sensor(std::vector<std::string> sensor_names,
182	    const char* sensor_name,
183	    get_sensor_fn_t get_sensor_fn,
184	    double setup_time)
185	{
186	    if (std::find(sensor_names.begin(), sensor_names.end(), sensor_name)
187	        == sensor_names.end())
188	        return false;
189	
190	    auto setup_timeout = std::chrono::steady_clock::now()
191	                         + std::chrono::milliseconds(int64_t(setup_time * 1000));
192	    bool lock_detected = false;
193	
194	    std::cout << "Waiting for \"" << sensor_name << "\": ";
195	    std::cout.flush();
196	
197	    while (true) {
198	        if (lock_detected and (std::chrono::steady_clock::now() > setup_timeout)) {
199	            std::cout << " locked." << std::endl;
200	            break;
201	        }
202	        if (get_sensor_fn(sensor_name).to_bool()) {
203	            std::cout << "+";
204	            std::cout.flush();
205	            lock_detected = true;
206	        } else {
207	            if (std::chrono::steady_clock::now() > setup_timeout) {
208	                std::cout << std::endl;
209	                throw std::runtime_error(
210	                    std::string("timed out waiting for consecutive locks on sensor \"")
211	                    + sensor_name + "\"");
212	            }
213	            std::cout << "_";
214	            std::cout.flush();
215	        }
216	        std::this_thread::sleep_for(std::chrono::milliseconds(100));
217	    }
218	
219	    std::cout << std::endl;
220	    return true;
221	}
